('old-data-berta2-all-20260501-01', 'recinMZzYcJs7t8DA', U&'Dot\00E9 d''un jardin et d''une terrasse, Le Chalet Kr\00E9ol est situ\00E9 \00E0 Saint-Joseph, \00E0 6 km de La Marine Langevin, \00E0 11 km de la Maison du Curcuma et \00E0 12 km de la cascade de Trou noir. Cet h\00E9bergement climatis\00E9 se trouve \00E0 1,1 km de la plage de Sable Noir. Vous b\00E9n\00E9ficierez d''un parking priv\00E9 sur place et d''une connexion Wi-Fi gratuite.\000A\000ACette maison de vacances comprend 2 chambres, une t\00E9l\00E9vision par c\00E2ble \00E0 \00E9cran plat, un lave-linge et une salle de bains pourvue d''une douche. Sa cuisine est \00E9quip\00E9e d''un micro-ondes et d''un r\00E9frig\00E9rateur. Les serviettes et le linge de lit sont fournis.\000A\000AVous pourrez profiter d''un spa.\000A\000ALa cascade de Grand Galet se trouve \00E0 14 km du Chalet Kr\00E9ol.', NULL, 'public', '0', 'Berta 2.0', U&'{"id":"recinMZzYcJs7t8DA","Nom commercial":"Le Chalet Kreol ","Raison sociale":"","Motif Hors ligne":"","En ligne":"non","Zone":"sud","Nom de la commune":"Saint-Joseph","Adresse":"10  Impasse Jean Moulin, 97480 Saint-Joseph","Site web":"","Groupe cat\00E9gorie":"H\00E9bergement","Nom cat\00E9gorie":"Location saisonni\00E8re","Nom sous cat\00E9gorie":"","Localisations":"","Code postal":"97480","Bureau postal":"Saint-Joseph","Lieux-dits":"","Prestations sur place":"climatisation , jardin , salle de bain priv\00E9e , TV , wifi , wifi gratuit","Prestations \00E0 proximit\00E9":"","Mode de paiement":"","Langues":"","Fixe":"","Mobile":"","Autre t\00E9l\00E9phone":"","Fax":"","E-Mail":"md.fontaine@sfr.fr","Capacit\00E9":"4","Classement":"","Accroche":"","Descriptif":"Dot\00E9 d''un jardin et d''une terrasse, Le Chalet Kr\00E9ol est situ\00E9 \00E0 Saint-Joseph, \00E0 6 km de La Marine Langevin, \00E0 11 km de la Maison du Curcuma et \00E0 12 km de la cascade de Trou noir. Cet h\00E9bergement climatis\00E9 se trouve \00E0 1,1 km de la plage de Sable Noir. Vous b\00E9n\00E9ficierez 